import{_ as s,o as i,c as n,a1 as p}from"./chunks/framework.BKJzsOC1.js";const k=JSON.parse('{"title":"栈、堆、虚拟内存与 Page Fault","description":"","frontmatter":{},"headers":[],"relativePath":"tech/cpp/memory-stack-heap-virtual.md","filePath":"tech/cpp/memory-stack-heap-virtual.md"}'),e={name:"tech/cpp/memory-stack-heap-virtual.md"};function l(t,a,h,c,o,d){return i(),n("div",null,[...a[0]||(a[0]=[p(`<h1 id="栈、堆、虚拟内存与-page-fault" tabindex="-1">栈、堆、虚拟内存与 Page Fault <a class="header-anchor" href="#栈、堆、虚拟内存与-page-fault" aria-label="Permalink to &quot;栈、堆、虚拟内存与 Page Fault&quot;">​</a></h1><p>“栈和堆”描述对象生命周期与分配方式；“虚拟内存和物理内存”描述操作系统与硬件怎样解释地址。它们不是两组互斥概念。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C++ 程序使用虚拟地址</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>进程虚拟地址空间</span></span>
<span class="line"><span>    ├── 代码与只读数据</span></span>
<span class="line"><span>    ├── 全局/静态数据</span></span>
<span class="line"><span>    ├── Heap</span></span>
<span class="line"><span>    ├── 内存映射区域</span></span>
<span class="line"><span>    └── 每个线程的 Stack</span></span>
<span class="line"><span>            ↓ 页表转换</span></span>
<span class="line"><span>物理内存</span></span></code></pre></div><hr><h2 id="一、线程栈与栈帧" tabindex="-1">一、线程栈与栈帧 <a class="header-anchor" href="#一、线程栈与栈帧" aria-label="Permalink to &quot;一、线程栈与栈帧&quot;">​</a></h2><p>每个线程通常拥有自己的调用栈。函数调用时建立栈帧，用来承载局部状态、保存的寄存器和返回信息。</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> functionA</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    functionB</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> functionB</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>functionA 调用 functionB：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Stack</span></span>
<span class="line"><span>┌────────────────┐</span></span>
<span class="line"><span>│ functionB      │</span></span>
<span class="line"><span>│ b = 20         │</span></span>
<span class="line"><span>│ 返回信息        │</span></span>
<span class="line"><span>├────────────────┤</span></span>
<span class="line"><span>│ functionA      │</span></span>
<span class="line"><span>│ a = 10         │</span></span>
<span class="line"><span>│ 返回信息        │</span></span>
<span class="line"><span>└────────────────┘</span></span></code></pre></div><p>functionB 返回后，其栈帧整体移除。这符合后进先出（LIFO）的嵌套生命周期。</p><h3 id="为什么栈分配通常很快" tabindex="-1">为什么栈分配通常很快 <a class="header-anchor" href="#为什么栈分配通常很快" aria-label="Permalink to &quot;为什么栈分配通常很快&quot;">​</a></h3><p>栈通常通过栈指针表示当前边界。为局部状态准备空间，概念上主要是调整栈指针；函数返回时再恢复。</p><p>它通常不需要搜索空闲块、为每个对象维护独立分配节点或合并碎片。不过编译器可能把变量放进寄存器，甚至完全优化掉，所以“局部变量一定物理存在于栈上”不是绝对规则。</p><h3 id="栈的限制" tabindex="-1">栈的限制 <a class="header-anchor" href="#栈的限制" aria-label="Permalink to &quot;栈的限制&quot;">​</a></h3><ul><li>每个线程的栈容量有限；</li><li>超大局部数组可能触发 Stack Overflow；</li><li>深递归不断增加栈帧；</li><li>栈天然适合嵌套生命周期，不适合函数返回后继续存在的对象。</li></ul><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bad</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::byte hugeBuffer[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1024</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1024</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // 很可能耗尽线程栈</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="二、堆与动态生命周期" tabindex="-1">二、堆与动态生命周期 <a class="header-anchor" href="#二、堆与动态生命周期" aria-label="Permalink to &quot;二、堆与动态生命周期&quot;">​</a></h2><p>动态分配使对象可以超越当前函数作用域：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> player </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make_unique</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Player</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;();</span></span></code></pre></div><p>需要区分智能指针对象和它管理的对象：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stack：unique_ptr 本身</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│ Player*          │</span></span>
<span class="line"><span>└──────────────────┘</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>Heap：Player 对象</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│ Player data      │</span></span>
<span class="line"><span>└──────────────────┘</span></span></code></pre></div><p>同样，局部 <code>vector</code> 的元数据通常在栈帧中，元素存储通常来自堆：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stack：vector 的 pointer / size / capacity</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>Heap：[10][20][30][40]</span></span></code></pre></div><p>“容器变量在栈上”不代表它管理的数据也在栈上。</p><h2 id="三、堆分配器做了什么" tabindex="-1">三、堆分配器做了什么 <a class="header-anchor" href="#三、堆分配器做了什么" aria-label="Permalink to &quot;三、堆分配器做了什么&quot;">​</a></h2><p>通用堆分配器需要：</p><ul><li>找到满足大小和对齐的空闲块；</li><li>记录分配大小和释放信息；</li><li>管理不同大小类别；</li><li>回收并合并空闲块；</li><li>处理多线程竞争；</li><li>必要时向操作系统申请更多虚拟内存。</li></ul><p>每次小型 <code>new</code> 通常不会直接进入内核。运行库分配器往往先从操作系统取得较大区域，再切成小块：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>操作系统提供较大区域</span></span>
<span class="line"><span>┌────────────────────────────────────┐</span></span>
<span class="line"><span>│                                    │</span></span>
<span class="line"><span>└────────────────────────────────────┘</span></span>
<span class="line"><span>              ↓ 分配器切分</span></span>
<span class="line"><span>┌──────┬──────────┬────┬────────────┐</span></span>
<span class="line"><span>│ 64B  │ 256B     │32B │ 空闲区域    │</span></span>
<span class="line"><span>└──────┴──────────┴────┴────────────┘</span></span></code></pre></div><h3 id="new-与-malloc" tabindex="-1"><code>new</code> 与 <code>malloc</code> <a class="header-anchor" href="#new-与-malloc" aria-label="Permalink to &quot;\`new\` 与 \`malloc\`&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Player</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> player </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Player</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(arguments);</span></span></code></pre></div><p>通常包含申请原始内存和执行构造函数。<code>delete</code> 先执行析构，再释放原始内存。</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> memory </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">malloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sizeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Player));</span></span></code></pre></div><p>只取得原始字节，不会自动建立 Player 对象生命周期。常规 C++ 业务代码应优先值语义、标准容器、智能指针和 RAII。</p><h2 id="四、虚拟地址空间" tabindex="-1">四、虚拟地址空间 <a class="header-anchor" href="#四、虚拟地址空间" aria-label="Permalink to &quot;四、虚拟地址空间&quot;">​</a></h2><p>程序中的指针通常保存虚拟地址。每个进程看到自己的虚拟地址空间：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程 A：虚拟地址 0x1000 → 物理页面 X</span></span>
<span class="line"><span>进程 B：虚拟地址 0x1000 → 物理页面 Y</span></span></code></pre></div><p>相同虚拟地址可以映射到不同物理内存。虚拟内存带来：</p><ul><li>进程隔离；</li><li>页面级读、写、执行权限；</li><li>按需分配物理页面；</li><li>文件映射与共享内存；</li><li>Copy-on-Write；</li><li>地址空间布局随机化。</li></ul><h2 id="五、page-与页表" tabindex="-1">五、Page 与页表 <a class="header-anchor" href="#五、page-与页表" aria-label="Permalink to &quot;五、Page 与页表&quot;">​</a></h2><p>内存映射通常按 Page 管理。常见基础页大小是 4 KB，但平台可以使用其他大小或大页。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟 Page 0 → 物理 Page 8</span></span>
<span class="line"><span>虚拟 Page 1 → 物理 Page 3</span></span>
<span class="line"><span>虚拟 Page 2 → 尚未映射</span></span></code></pre></div><p>页表项通常还记录页面是否存在、是否可读写、是否可执行、是否被访问或修改。</p><p>虚拟地址可概念性地拆成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟页号 + 页内偏移</span></span></code></pre></div><p>CPU 通过页表找到物理页，再加上页内偏移得到最终物理地址。</p><h2 id="六、tlb-与-cpu-cache" tabindex="-1">六、TLB 与 CPU Cache <a class="header-anchor" href="#六、tlb-与-cpu-cache" aria-label="Permalink to &quot;六、TLB 与 CPU Cache&quot;">​</a></h2><p>逐次遍历页表成本很高，CPU 使用 TLB（Translation Lookaside Buffer）缓存最近的地址转换：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>虚拟页号</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>查询 TLB</span></span>
<span class="line"><span>    ├── 命中：快速得到物理页</span></span>
<span class="line"><span>    └── 未命中：执行页表遍历</span></span></code></pre></div><p>TLB 和 CPU Cache 作用不同：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TLB：缓存虚拟页到物理页的转换</span></span>
<span class="line"><span>CPU Cache：缓存实际数据和指令</span></span></code></pre></div><p>访问大量分散页面可能同时增加 TLB Miss 和 Cache Miss。</p><h2 id="七、page-fault-不一定是错误" tabindex="-1">七、Page Fault 不一定是错误 <a class="header-anchor" href="#七、page-fault-不一定是错误" aria-label="Permalink to &quot;七、Page Fault 不一定是错误&quot;">​</a></h2><p>CPU 遇到当前页表无法直接完成的访问，会触发 Page Fault 并把控制权交给操作系统。</p><h3 id="demand-paging" tabindex="-1">Demand Paging <a class="header-anchor" href="#demand-paging" aria-label="Permalink to &quot;Demand Paging&quot;">​</a></h3><p>程序已经保留虚拟地址，但页面尚未配备物理内存：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一次写入页面</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Page Fault</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>操作系统分配物理页并建立映射</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>重新执行原指令</span></span></code></pre></div><h3 id="文件映射" tabindex="-1">文件映射 <a class="header-anchor" href="#文件映射" aria-label="Permalink to &quot;文件映射&quot;">​</a></h3><p>内存映射文件的页面首次访问时，系统可能读取对应文件内容并建立映射。</p><h3 id="copy-on-write" tabindex="-1">Copy-on-Write <a class="header-anchor" href="#copy-on-write" aria-label="Permalink to &quot;Copy-on-Write&quot;">​</a></h3><p>多个执行环境先共享只读页面；某一方写入时触发 Page Fault，系统复制页面，再让写入发生在私有副本上。</p><h3 id="非法访问" tabindex="-1">非法访问 <a class="header-anchor" href="#非法访问" aria-label="Permalink to &quot;非法访问&quot;">​</a></h3><p>如果地址没有合法映射或权限不允许，系统无法修复，就会报告 Segmentation Fault 或 Access Violation。</p><blockquote><p>Page Fault 是硬件请求操作系统处理页面状态的机制；只有无法合法处理时，才表现为程序访问错误。</p></blockquote><h2 id="八、minor-与-major-page-fault" tabindex="-1">八、Minor 与 Major Page Fault <a class="header-anchor" href="#八、minor-与-major-page-fault" aria-label="Permalink to &quot;八、Minor 与 Major Page Fault&quot;">​</a></h2><p>Minor Page Fault 通常不需要从磁盘读取，例如按需分配零页、建立已有页面映射或 Copy-on-Write。它仍需要进入内核处理。</p><p>Major Page Fault 需要从较慢的存储设备读取页面，例如文件映射内容当前不在物理内存。其延迟对实时系统尤其危险。</p><p>移动平台的交换和内存回收策略各不相同；内存压力过大时，应用还可能被系统直接终止。</p><h2 id="九、申请内存与首次触碰" tabindex="-1">九、申请内存与首次触碰 <a class="header-anchor" href="#九、申请内存与首次触碰" aria-label="Permalink to &quot;九、申请内存与首次触碰&quot;">​</a></h2><p>保留较大的虚拟地址范围，不代表所有物理页面都已立即建立。逐页第一次写入时，可能才真正触发物理页面提交：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">size_t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> buffer.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    buffer[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::byte{</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>性能分析应区分：</p><ul><li>保留虚拟地址；</li><li>提交或映射物理页面；</li><li>第一次触碰页面；</li><li>后续缓存访问。</li></ul><p>某些实时系统会在加载阶段预触碰内存，把 Page Fault 从关键帧移动到可控阶段。</p><h2 id="十、栈也建立在虚拟内存上" tabindex="-1">十、栈也建立在虚拟内存上 <a class="header-anchor" href="#十、栈也建立在虚拟内存上" aria-label="Permalink to &quot;十、栈也建立在虚拟内存上&quot;">​</a></h2><p>线程栈通常是虚拟地址空间中的一个保留区域。系统可以只在栈实际增长时提交物理页，并在边界放置 Guard Page：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常 Stack 页面</span></span>
<span class="line"><span>正常 Stack 页面</span></span>
<span class="line"><span>Guard Page（不可访问）</span></span></code></pre></div><p>越界进入 Guard Page 时可以尽早检测 Stack Overflow。</p><h2 id="十一、内存碎片" tabindex="-1">十一、内存碎片 <a class="header-anchor" href="#十一、内存碎片" aria-label="Permalink to &quot;十一、内存碎片&quot;">​</a></h2><h3 id="外部碎片" tabindex="-1">外部碎片 <a class="header-anchor" href="#外部碎片" aria-label="Permalink to &quot;外部碎片&quot;">​</a></h3><p>总空闲量足够，但被分散为多个小块：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[使用20][空闲10][使用30][空闲15][使用25][空闲20]</span></span></code></pre></div><p>总空闲为 45，却没有连续 40 的块。</p><h3 id="内部碎片" tabindex="-1">内部碎片 <a class="header-anchor" href="#内部碎片" aria-label="Permalink to &quot;内部碎片&quot;">​</a></h3><p>请求 33 字节，分配器因对齐或大小类别提供 48 或 64 字节；块内未使用部分就是内部碎片。</p><p>大量分散的小对象还会增加页表、缓存和分配元数据成本，即使有效数据总量并不大。</p><h2 id="十二、专用分配器" tabindex="-1">十二、专用分配器 <a class="header-anchor" href="#十二、专用分配器" aria-label="Permalink to &quot;十二、专用分配器&quot;">​</a></h2><h3 id="linear-arena-allocator" tabindex="-1">Linear/Arena Allocator <a class="header-anchor" href="#linear-arena-allocator" aria-label="Permalink to &quot;Linear/Arena Allocator&quot;">​</a></h3><p>在预分配区域中顺序推进，最后整体重置：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[已使用数据][下一个位置 →][空闲空间]</span></span></code></pre></div><p>适合单帧临时数据、一次加载流程和解析中间结果，不适合任意顺序单独释放。</p><h3 id="pool-allocator" tabindex="-1">Pool Allocator <a class="header-anchor" href="#pool-allocator" aria-label="Permalink to &quot;Pool Allocator&quot;">​</a></h3><p>把内存切成固定大小槽位：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Slot][Slot][Slot][Slot]</span></span></code></pre></div><p>适合粒子、组件、任务节点等同尺寸且频繁创建销毁的对象。</p><h3 id="frame-allocator" tabindex="-1">Frame Allocator <a class="header-anchor" href="#frame-allocator" aria-label="Permalink to &quot;Frame Allocator&quot;">​</a></h3><p>帧内顺序分配，等相关 CPU/GPU 工作完成后整体重置。CPU 与 GPU 跨帧并行时，需要双缓冲、三缓冲或 Fence，不能在 CPU 帧结束时立即复用仍被 GPU 访问的内存。</p><h2 id="十三、移动端约束" tabindex="-1">十三、移动端约束 <a class="header-anchor" href="#十三、移动端约束" aria-label="Permalink to &quot;十三、移动端约束&quot;">​</a></h2><p>移动设备需要同时考虑：</p><ul><li>进程内存预算与峰值；</li><li>CPU/GPU 共享内存带宽；</li><li>Texture、Buffer 与临时解压数据；</li><li>后台切换和系统资源回收；</li><li>低内存警告与系统终止；</li><li>温控降频后的持续性能。</li></ul><p>统一内存架构不表示资源没有同步和带宽成本，也不意味着 CPU/GPU 可以无限制并发访问。</p><hr><h2 id="本章结论" tabindex="-1">本章结论 <a class="header-anchor" href="#本章结论" aria-label="Permalink to &quot;本章结论&quot;">​</a></h2><ol><li>栈和堆通常都位于进程的虚拟地址空间。</li><li>栈适合嵌套生命周期，堆支持动态生命周期但管理成本更复杂。</li><li>局部容器可以在栈上，而其元素存储位于堆上。</li><li>CPU 通过页表把虚拟地址转换为物理地址，TLB 缓存转换结果。</li><li>Page Fault 可以是按需分配、文件映射、Copy-on-Write，也可以是非法访问。</li><li>外部碎片是空闲块分散，内部碎片是分配块大于实际需求。</li><li>专用分配器的价值是让生命周期、延迟和预算更可预测。</li><li>实时系统不仅关心占用量，还关心分配、首次触碰和释放发生在什么时刻。</li></ol><p><a href="./map-unordered-map.html">← 上一章：map、unordered_map 与 rehash</a> · <a href="./memory-safety-debugging.html">下一章：内存安全、OOM 与诊断 →</a></p>`,104)])])}const g=s(e,[["render",l]]);export{k as __pageData,g as default};
